import React, { useEffect, useState } from 'react';
import { streamxApi } from '../services/api';

export default function DiscussionsPage() {
  const [items, setItems] = useState([]);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');

  const load = async () => {
    const res = await streamxApi.getDiscussions();
    setItems(res.data || []);
  };

  useEffect(() => {
    load().catch(() => setItems([]));
  }, []);

  const submit = async (e) => {
    e.preventDefault();
    if (!title.trim() || !content.trim()) return;
    await streamxApi.createDiscussion({
      title,
      content,
      category: 'Discussion',
      movieTitle: '',
      rating: 5,
      containsSpoiler: false
    });
    setTitle('');
    setContent('');
    await load();
  };

  return (
    <main style={{ paddingTop: '96px', padding: '96px 24px 24px' }}>
      <h1 style={{ marginBottom: '16px' }}>Discussions</h1>
      <form onSubmit={submit} style={{ display: 'grid', gap: '10px', marginBottom: '20px', maxWidth: '720px' }}>
        <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder='Title' className='input' />
        <textarea value={content} onChange={(e) => setContent(e.target.value)} placeholder='Share your thoughts' className='input' rows={4} />
        <button className='btn btn-red' type='submit'>Create Post</button>
      </form>
      <div style={{ display: 'grid', gap: '12px' }}>
        {items.map((d) => (
          <article key={d._id} style={{ background: '#121212', border: '1px solid #282828', borderRadius: '10px', padding: '14px' }}>
            <h3 style={{ margin: '0 0 6px 0' }}>{d.title}</h3>
            <p style={{ margin: '0 0 8px 0', color: '#c3c3c3' }}>{d.content}</p>
            <small style={{ color: '#8d8d8d' }}>{d.user?.name || d.user?.username || 'User'} • {d.status}</small>
          </article>
        ))}
      </div>
    </main>
  );
}
